mapper.select:
SELECT al.user_id, al.artifact_id, al.liked_at AS likedAt,
       u.username, u.avatar_url AS userAvatar,
       a.title_zh AS artifactName, a.image_url AS artifactImage
FROM artifact_likes al
LEFT JOIN users u ON al.user_id = u.id
LEFT JOIN artifacts a ON al.artifact_id = a.id

    AND al.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')


        AND al.liked_at >= #{startTime}


        AND al.liked_at <= #{endTime}


ORDER BY al.liked_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM artifact_likes al
LEFT JOIN users u ON al.user_id = u.id

    AND al.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')


        AND al.liked_at >= #{startTime}


        AND al.liked_at <= #{endTime}
